local LxBaseState = require("LApp.component.fsm.LxBaseState")
---@class LBattlePlayState:LxBaseState
local LBattlePlayState = classX("LBattlePlayState", LxBaseState)

function LBattlePlayState:ctor()
    self._stateType = BattleFsmState.Play
end

function LBattlePlayState:Initialize()
    ---@type LBattleFsm
    self._battleFsm = self:GetMachine()
    ---@type LBattleLogicMgr
    self._logicMgr = self._battleFsm:GetVar("BattleLogicMgr")
    ---@type LFightReportData
    self._reportData = self._logicMgr:GetReportData()
    ---@type LFightRoundData
    self._roundData = nil
    ---@type LFightBoutData
    self._boutData = nil
    ---@type LBattleBoutActionListData
    self._actionListData = nil

    self._roundIdx = 0
    self._roundCount = 0
    self._boutIdx = 0
    self._boutCount = 0
    self._actionIdx = 0
    self._actionCount = 0


    self._bRunning = false
    self._isNextReady = false
end

function LBattlePlayState:Enter()
    self._bRunning = true

end

function LBattlePlayState:Exit()
    self._bRunning = false
end

function LBattlePlayState:Reset()
    self._bRunning = true
    self._roundIdx = 0
    self._roundCount = 0
    self._boutIdx = 0
    self._boutCount = 0
    self._actionIdx = 0
    self._actionCount = 0
    self._roundData = nil
    self._boutData = nil
    self._actionListData = nil
end

function LBattlePlayState:NextRound()
    self._roundData = self._reportData:GetRound(self._roundIdx + 1)
    if self._roundData then
        self._roundIdx = self._roundIdx + 1
        self._reportData:SetRoundIdx(self._roundIdx)
        self._roundCount = self._reportData:GetTotalRound()
        self._boutIdx = 0
        self._boutData = nil

        if self._logicMgr then
            self._logicMgr:PlayRound(self._roundIdx, self._roundData)
        end
    end

    return self._roundData
end

function LBattlePlayState:NextBout()
    if not self._roundData then
        return nil
    end
    self._boutData = self._roundData:GetBout(self._boutIdx + 1)
    if self._boutData then
        self._boutIdx = self._boutIdx + 1
        self._boutCount = self._roundData:GetBoutCount()
        self._actionIdx = 0
        self._actionListData = nil

        if self._logicMgr then
            self._logicMgr:PlayBout(self._roundIdx, self._boutIdx, self._boutData)
        end
    end

    return self._boutData
end

function LBattlePlayState:NextAction()
    if not self._boutData then
        return nil
    end

    self._actionListData = self._boutData:GetAction(self._actionIdx + 1)
    if self._actionListData then
        self._actionCount = self._boutData:GetActionTotalCount()
        self._actionIdx = self._actionIdx + 1
    end

    return self._actionListData
end

function LBattlePlayState:Execute(deltaTime)
    --- is any ready
    self._isNextReady = self._battleFsm:GetVar("NextReady")
    if not self._isNextReady then return end

    if not self._bRunning then return end

    if not self._reportData then return end

    --- try get round
    if not self._roundData then
        self._roundData = self:NextRound()
        if not self._roundData then
            if self._reportData.isReportEnd then
                self._bRunning = false
                self._logicMgr:OnLogicBattleEnd()
            else
                self._reportData:SetRoundIdx(self._roundIdx + 1)
                self:RequestNext()
            end
            return
        end
    end
    --- try get bout
    if not self._boutData then
        self._boutData = self:NextBout()
        if not self._boutData then
            if self._reportData.isReportEnd or self._reportData:HasRound(self._roundIdx + 1) then
                self._roundData = nil
                self:Execute(0)
            else
                self:RequestNext()
            end
            return
        end
    end
    --- try get action
    self._actionListData = self:NextAction()
    if not self._actionListData then
        self._boutData = nil
        self:Execute(0)
        return
    end

    --- play actions
    if self._logicMgr then
        self._logicMgr:PlayActionList(self._boutData, self._actionIdx, self._actionListData)
    else
        self._bRunning = false
    end
end

function LBattlePlayState:RequestNext()
    if self._logicMgr then
        self._logicMgr:RequestNext()
    end
end



return LBattlePlayState